window.__customContextMenuInitialized=true;let menu=null;let currentLink=null;let currentSelectedText='';let tabsBarOverlay=null;let sidebarStatePersistTimer=0;const sidebarStateStorageKey='site-sidebar-collapse-state';const rootSidebarClasses={primary:'site-sidebar-primary-collapsed',secondary:'site-sidebar-secondary-collapsed'};const viewportBreakpoints={desktopMinWidth:1200};function getTabsBar(){return document.querySelector('.md-tabs');}
