if(!isMobileViewport){items.push({action:'toggle-primary-sidebar',label:sidebarState.primary?'展开左侧目录':'折叠左侧目录'});items.push({action:'toggle-secondary-sidebar',label:sidebarState.secondary?'展开右侧目录':'折叠右侧目录'});items.push({action:'toggle-both-sidebars',label:(sidebarState.primary&&sidebarState.secondary)?'展开两侧目录':'折叠两侧目录'});}
